insert into offmarket.business_scores (business_id, score_run_id, layer1_base_rate, layer1_comment, layer2_sellability, layer2_comment, layer3_behavioral_trigger, layer3_comment, layer4_market_pull, layer4_comment, final_score, final_tier, final_comment, value_add_thesis, confidence, data_completeness) values
('6a637774-0368-5366-930e-c67aa2dd1967', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 78, 'Dr. Buchanan has practiced general dentistry in Dallas since 1987 (~37-39 yrs; Baylor College of Dentistry); tenure proxy ~62-66 — squarely in the natural-exit window. Solo owner-operator; no associate named. Medium confidence (proxy age).', 78, 'Clean ~37-yr solo family/cosmetic practice on Greenville Ave near Lake Highlands, AGD Fellow, large positive review base (1,437 ratings on WebMD, 5.0 avg), recurring hygiene base — very sellable solo practice; SBA-financeable.', 66, 'Coasting tells: sole listed provider with no associate, longstanding single location, dated web brand, no visible recent expansion or hiring, founder near a natural exit. Healthy practice, disengaged-growth posture.', 84, 'Lake Highlands / NE Dallas is a desirable, established catchment; a clean solo GP with a loyal base is a prime SBA-financed acquisition and a sought-after target for the buyer community.', 75, 'B_forward', 'Dr. Barry H. Buchanan, ~63 (license_tenure_proxy), runs Barry H. Buchanan, DDS in Dallas, Dallas County. Dr. Buchanan has practiced general dentistry in Dallas since 1987 (~37-39 yrs; Baylor College of Dentistry); tenure proxy ~62-66 — squarely in the natural-exit window. Solo owner-operator; no associate named. Medium confidence (proxy age). Coasting tells: sole listed provider with no associate, longstanding single location, dated web brand, no visible recent expansion or hiring, founder near a natural exit. Healthy practice, disengaged-growth posture. Lake Highlands / NE Dallas is a desirable, established catchment; a clean solo GP with a loyal base is a prime SBA-financed acquisition and a sought-after target for the buyer community. Composite 75/100. Tier B — hand to the buyer / searcher community.', 'AI front desk + recall automation + online scheduling + modern PMS + automated reviews; associate-to-owner transition — credible 1.5-2x EBITDA path over 18-24 months.', 'medium', 0.55),
('16d04d3f-3463-534a-a689-56bc2f882561', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 84, 'Dr. Parish earned his DDS from Baylor College of Dentistry in 1986 and has practiced from the same location since November 1986 (~39 yrs) — tenure proxy ~64-67, squarely in the natural-exit window; solo owner with no associate. Strong base-rate signal. Medium confidence (proxy age).', 72, 'Clean ~39-yr solo general dentistry practice (incl. dentures) in the Carrollton/Addison/North Dallas area, recurring hygiene base, loyal long-term patients, clean record — solid sellable solo practice; SBA-financeable. Smaller footprint caps it modestly.', 70, 'Strong coasting profile: same location for 39 years, sole listed provider with no associate, dated web presence, no visible recent expansion or hiring, owner near a natural exit. Healthy, disengaged-growth — not distress.', 83, 'North Dallas / Carrollton corridor is an active DSO/PE catchment; a clean long-tenured solo GP there is a clean SBA-financed bolt-on and an attractive forward to searchers.', 77, 'B_forward', 'Dr. Grant K. Parish, ~65 (license_tenure_proxy), runs Grant K. Parish, DDS in Dallas, Dallas County. Dr. Parish earned his DDS from Baylor College of Dentistry in 1986 and has practiced from the same location since November 1986 (~39 yrs) — tenure proxy ~64-67, squarely in the natural-exit window; solo owner with no associate. Strong base-rate signal. Medium confidence (proxy age). Strong coasting profile: same location for 39 years, sole listed provider with no associate, dated web presence, no visible recent expansion or hiring, owner near a natural exit. Healthy, disengaged-growth — not distress. North Dallas / Carrollton corridor is an active DSO/PE catchment; a clean long-tenured solo GP there is a clean SBA-financed bolt-on and an attractive forward to searchers. Composite 77/100. Tier B — hand to the buyer / searcher community.', 'AI front desk + recall automation + online scheduling + modern PMS + automated reviews; associate-to-owner transition — credible 1.5-2x EBITDA path over 18-24 months.', 'medium', 0.55),
('cd522c70-8ce7-52e0-b426-90fc00e72bcf', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 76, 'Dr. Hubbard earned his DDS from Baylor College of Dentistry in 1987 (Texas A&M 1982) — ~38-39 yrs licensed; tenure proxy ~62-65, in the natural-exit window. A second dentist (Dr. Lyle Petrutsas) is on staff, which gives a built-in transition vehicle. Medium confidence (proxy age).', 84, 'Strong asset: a ~37-yr cosmetic/family practice serving Highland Park/University Park/Preston Hollow, 2 providers, ~10 staff, 124-168 reviews across platforms, media-featured cosmetic reputation, clean record — very sellable and bankable in a premium catchment.', 58, 'Some coasting tells (founder near exit; no recent expansion beyond the existing associate), but a cosmetic-driven Park Cities practice that''s still media-visible and actively marketing isn''t strongly ''disengaged''. Moderate L3.', 88, 'Park Cities / Uptown Dallas is a top buy-side target — premium cosmetic catchment, easy SBA financing, strong DSO and individual-buyer demand.', 74, 'B_forward', 'Dr. Jeffrey W. Hubbard, ~62 (license_tenure_proxy), runs Park Cities Family Dentistry, P.A. (Jeffrey W. Hubbard, DDS) in Dallas, Dallas County. Dr. Hubbard earned his DDS from Baylor College of Dentistry in 1987 (Texas A&M 1982) — ~38-39 yrs licensed; tenure proxy ~62-65, in the natural-exit window. A second dentist (Dr. Lyle Petrutsas) is on staff, which gives a built-in transition vehicle. Medium confidence (proxy age). Some coasting tells (founder near exit; no recent expansion beyond the existing associate), but a cosmetic-driven Park Cities practice that''s still media-visible and actively marketing isn''t strongly ''disengaged''. Moderate L3. Park Cities / Uptown Dallas is a top buy-side target — premium cosmetic catchment, easy SBA financing, strong DSO and individual-buyer demand. Composite 74/100. Tier B — hand to the buyer / searcher community.', 'AI front desk + concierge recall, online scheduling, structured cosmetic-case marketing, modern PMS, plus an associate-to-equity glide path with Dr. Petrutsas — the brand supports premium pricing, so the lever is throughput and case acceptance.', 'medium', 0.6),
('01b01f6b-3f55-59d8-bcf2-b4d8053359dd', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 28, 'Dr. Vanderbrook (Baylor College of Dentistry DDS) appears clearly mid-career; tenure proxy ~40-46 — not near a natural-exit window. Low L1.', 70, 'Clean Lakewood-area (Mockingbird Ln) general/family/implant practice, Saturday hours, recurring hygiene base, decent reviews — a real, financeable practice, just a younger one. Modest target.', 26, 'No coasting tells — active marketing, Saturday hours (a growth posture, not a retreat), mid-career owner. Low L3.', 84, 'Lakewood / East Dallas 75214 is a desirable catchment with strong DSO interest, but a younger solo practice draws less acquisition intensity.', 46, 'C_watch', 'Dr. Drew Vanderbrook, ~43 (license_tenure_proxy), runs Vanderbrook Family Dentistry (Drew Vanderbrook, DDS) in Dallas, Dallas County. Dr. Vanderbrook (Baylor College of Dentistry DDS) appears clearly mid-career; tenure proxy ~40-46 — not near a natural-exit window. Low L1. No coasting tells — active marketing, Saturday hours (a growth posture, not a retreat), mid-career owner. Low L3. Lakewood / East Dallas 75214 is a desirable catchment with strong DSO interest, but a younger solo practice draws less acquisition intensity. Composite 46/100. Tier C — re-score in ~90 days.', 'N/A near-term — owner not winding down. Watch.', 'low', 0.4),
('e8813434-200b-5b23-980b-66f682e5fc3b', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 40, 'The practice has run ~30 yrs (patients report ''almost 25 yrs with the same dentist'' — suggesting a prior owner), but current owner Dr. Iranmehr earned her DDS in 2003 (~23 yrs licensed; ~15 yrs as owner) — tenure proxy ~46-50, not yet at a natural-exit window. Low-medium L1.', 78, 'Clean, well-reviewed (76 Yelp / 354 Birdeye) ~30-yr North Dallas/Preston Rd general/family practice with a strong recurring base, ~7 staff, clean record — genuinely sellable and bankable; the constraint is the owner''s age.', 40, 'Mixed: established practice with continuity, but the owner is mid-career and there''s no strong decline stack — moderate-low L3.', 85, 'Far North Dallas / Preston Rd corridor is a hot DSO/PE catchment; a 30-yr practice with 350+ reviews is a prized bolt-on.', 56, 'C_watch', 'Dr. Mehrnaz Iranmehr, ~48 (license_tenure_proxy), runs Preston Family Dentistry (Mehrnaz Iranmehr, DDS) in Dallas, Dallas County. The practice has run ~30 yrs (patients report ''almost 25 yrs with the same dentist'' — suggesting a prior owner), but current owner Dr. Iranmehr earned her DDS in 2003 (~23 yrs licensed; ~15 yrs as owner) — tenure proxy ~46-50, not yet at a natural-exit window. Low-medium L1. Mixed: established practice with continuity, but the owner is mid-career and there''s no strong decline stack — moderate-low L3. Far North Dallas / Preston Rd corridor is a hot DSO/PE catchment; a 30-yr practice with 350+ reviews is a prized bolt-on. Composite 56/100. Tier C — re-score in ~90 days.', 'If/when the owner is ready: AI front desk + recall automation + modern PMS; for now this is a ''watch / forward to a DSO that does partnership buyouts'' rather than a near-term Gideon acquisition.', 'low', 0.45),
('82ccf993-4120-5ca3-ae36-f2bbbb3e4b64', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 35, 'The practice has served East Dallas for 65+ yrs, but Dr. Slaughter only took it over in 2009 (~17 yrs as owner) and is mid-career — tenure proxy ~44-50, not at a natural-exit window. Low-medium L1.', 76, 'Clean 65+-yr Lakewood general/family/cosmetic/implant practice with a deep multigenerational patient base, recurring revenue, clean record — a real, financeable, attractive practice; the owner just isn''t a seller.', 30, 'Not coasting — active marketing, well-maintained presence, mid-career owner who recently took the practice over. Low L3.', 84, 'Lakewood / East Dallas 75214 is a desirable, in-demand catchment with strong DSO interest.', 51, 'C_watch', 'Dr. Reid Slaughter, ~47 (license_tenure_proxy), runs Lakewood Family Dental Care (Reid Slaughter, DDS) in Dallas, Dallas County. The practice has served East Dallas for 65+ yrs, but Dr. Slaughter only took it over in 2009 (~17 yrs as owner) and is mid-career — tenure proxy ~44-50, not at a natural-exit window. Low-medium L1. Not coasting — active marketing, well-maintained presence, mid-career owner who recently took the practice over. Low L3. Lakewood / East Dallas 75214 is a desirable, in-demand catchment with strong DSO interest. Composite 51/100. Tier C — re-score in ~90 days.', 'N/A near-term — recent-ish owner, mid-career. Watch.', 'low', 0.4),
('740488e7-4c41-5620-b501-09158359159f', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 45, 'Lead dentist Dr. Milenbaugh''s tenure, age, and how long the practice has operated are not verified — treat as a neutral/uncertain base rate. Low confidence; needs a TSBDE issue-date check.', 72, 'A real, operating East Dallas (White Rock area) general + restorative + cosmetic practice with in-house specialty support — financeable and a recurring-revenue business, pending verification of size and ownership.', 42, 'No verified coasting tells; reasonably maintained web presence. Moderate-low L3, low confidence.', 84, 'East Dallas / White Rock 75218 is a desirable catchment with DSO interest.', 57, 'C_watch', 'Dr. Milenbaugh (lead dentist), age unknown, runs Dallas Dental Specialists / Family Dentist (Milenbaugh) in Dallas, Dallas County. Lead dentist Dr. Milenbaugh''s tenure, age, and how long the practice has operated are not verified — treat as a neutral/uncertain base rate. Low confidence; needs a TSBDE issue-date check. No verified coasting tells; reasonably maintained web presence. Moderate-low L3, low confidence. East Dallas / White Rock 75218 is a desirable catchment with DSO interest. Composite 57/100. Tier C — re-score in ~90 days.', 'Pending verification: standard recall/AI/scheduling/PMS stack. Verify owner age and practice age before acting.', 'low', 0.3),
('7ea8b0ae-45ed-5b69-850d-884fc3ce345e', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 92, 'Dr. LaCroix earned his DDS from UT Health Science Center Houston in 1978 (~48 yrs licensed) and has practiced family dentistry in Westlake Hills for 36+ yrs — tenure proxy ~70-73, deep in the natural-exit window; solo owner with no associate. The single cleanest base-rate signal in this run. Medium confidence (proxy age, but strongly corroborated).', 78, 'Clean ~36-yr solo general/family/pediatric/cosmetic practice in affluent Westlake Hills (78746), in ''The School Yard'' building, recurring hygiene base, founding member of the Capital Area Dental Foundation, clean record — a highly sellable, bankable solo practice in a premium ZIP.', 72, 'Strong coasting profile: solo provider with no associate, 36+ yrs in the same area/building, dated web presence, no visible recent expansion or hiring, owner well past typical retirement age. Healthy practice, classic pre-sale disengaged-growth posture — not distress.', 88, 'Westlake Hills / Bee Caves Rd is a premium Austin catchment; Austin is a top-3 active DSO/PE dental market and a clean long-tenured solo GP in 78746 is a prime SBA-financed acquisition and a hotly-sought forward to searchers.', 82, 'A_acquire_self', 'Dr. Stanley LaCroix, ~71 (license_tenure_proxy), runs Stanley LaCroix, DDS, P.C. (LaCroix Family Dental) in West Lake Hills, Travis County. Dr. LaCroix earned his DDS from UT Health Science Center Houston in 1978 (~48 yrs licensed) and has practiced family dentistry in Westlake Hills for 36+ yrs — tenure proxy ~70-73, deep in the natural-exit window; solo owner with no associate. The single cleanest base-rate signal in this run. Medium confidence (proxy age, but strongly corroborated). Strong coasting profile: solo provider with no associate, 36+ yrs in the same area/building, dated web presence, no visible recent expansion or hiring, owner well past typical retirement age. Healthy practice, classic pre-sale disengaged-growth posture — not distress. Westlake Hills / Bee Caves Rd is a premium Austin catchment; Austin is a top-3 active DSO/PE dental market and a clean long-tenured solo GP in 78746 is a prime SBA-financed acquisition and a hotly-sought forward to searchers. Composite 82/100. Tier A — Gideon should pursue this one directly.', 'AI front desk + recall automation to reactivate the lapsed-hygiene base, online scheduling, modern PMS migration, automated reviews, plus immediate associate hire on a buy-in path — a credible 1.5-2x EBITDA path over 18-24 months in a premium, supply-constrained catchment.', 'medium', 0.6)
